import{_ as a,o as t,c as o,a3 as i}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"XiHan.Framework.ObjectStorage","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/object-storage.md","filePath":"cosmos/framework/packages/object-storage.md","lastUpdated":1783216089000}'),d={name:"cosmos/framework/packages/object-storage.md"};function r(s,e,l,c,n,h){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="xihan-framework-objectstorage" tabindex="-1">XiHan.Framework.ObjectStorage <a class="header-anchor" href="#xihan-framework-objectstorage" aria-label="Permalink to &quot;XiHan.Framework.ObjectStorage&quot;">​</a></h1><blockquote><p>对象存储：本地磁盘与阿里云 OSS / MinIO / 腾讯云 COS 的统一适配抽象，支持多提供程序路由。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.ObjectStorage</code></li><li><strong>模块类</strong>：<code>XiHanObjectStorageModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.ObjectStorage 把「文件存到哪里」这件事抽象成一个统一接口 <code>IFileStorageProvider</code>：不管底层是本地磁盘、阿里云 OSS、MinIO 还是腾讯云 COS，业务代码都用同一套上传、下载、删除、生成预签名 URL 的方法。你可以同时启用多个提供程序，并按业务路由键把不同类型的文件（如头像、附件）分发到不同的存储后端。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要文件上传/下载能力，但不想把代码绑死在某一家云厂商上。</li><li>想在本地开发用磁盘存储、上线切换到 OSS/COS/MinIO，只改配置不改代码。</li><li>需要分片上传、断点续传、预签名临时访问 URL、文件复制/移动等常见对象存储操作。</li><li>需要按业务把不同文件路由到不同存储桶或不同提供程序。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.ObjectStorage</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanObjectStorageModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 中调用 <code>services.AddXiHanObjectStorage(config)</code>，从配置读取要启用哪些提供程序及默认提供程序。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>统一存储抽象</strong>：<code>IFileStorageProvider</code> 定义上传、下载、删除、存在性检查、获取元数据、复制、移动、列举目录等操作，四种后端实现同一接口。</li><li><strong>多提供程序管理</strong>：<code>IFileStorageProviderManager</code> 按名称取出对应提供程序，可查询已注册的提供程序名。</li><li><strong>业务路由</strong>：<code>IFileStorageRouter</code> 按业务路由键（如 <code>avatar</code>、<code>attachment</code>）解析并选择目标提供程序，支持严格匹配开关。</li><li><strong>分片与断点续传</strong>：<code>IFileStorageProvider</code> 暴露初始化/上传分片/完成/取消分片上传方法，提供程序通过 <code>SupportChunkedUpload</code> / <code>SupportResumableUpload</code> 声明能力。</li><li><strong>预签名 URL</strong>：<code>GeneratePresignedUrlAsync</code> 生成带过期时间的临时访问链接。</li><li><strong>本地存储直链</strong>：本地提供程序默认落在 <code>wwwroot/uploads</code> 下，配合 Web 静态文件服务可直接通过 URL 前缀访问。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>IFileStorageProvider</code> / <code>FileStorageProviderBase</code></td><td>存储提供程序接口与基类</td></tr><tr><td><code>LocalFileStorageProvider</code></td><td>本地磁盘存储（<code>ProviderName = &quot;Local&quot;</code>）</td></tr><tr><td><code>AliyunOssStorageProvider</code></td><td>阿里云 OSS（<code>&quot;AliyunOSS&quot;</code>）</td></tr><tr><td><code>MinioFileStorageProvider</code></td><td>MinIO（<code>&quot;MinIO&quot;</code>）</td></tr><tr><td><code>TencentCosStorageProvider</code></td><td>腾讯云 COS（<code>&quot;TencentCOS&quot;</code>）</td></tr><tr><td><code>IFileStorageProviderManager</code> / <code>DefaultFileStorageProviderManager</code></td><td>按名称获取提供程序</td></tr><tr><td><code>IFileStorageRouter</code> / <code>DefaultFileStorageRouter</code></td><td>按业务路由键选择提供程序</td></tr></tbody></table><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置节</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHan:ObjectStorage</code></td><td>全局：<code>DefaultProvider</code>、<code>EnabledProviders</code>、<code>RouteProviderMappings</code>、<code>StrictRouteMatch</code></td></tr><tr><td><code>XiHan:ObjectStorage:Local</code></td><td>本地：<code>RootPath</code>（默认 <code>wwwroot/uploads</code>）、<code>UrlPrefix</code>（默认 <code>/uploads</code>）</td></tr><tr><td><code>XiHan:ObjectStorage:AliyunOss</code> / <code>:Minio</code> / <code>:TencentCos</code></td><td>对应云存储的接入参数</td></tr></tbody></table><blockquote><p>本地存储配置节 <code>XiHan:ObjectStorage:Local</code>（<code>RootPath</code> / <code>UrlPrefix</code>）也被 Web.Api 用于挂载静态文件服务，实现上传文件的直链访问。</p></blockquote><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li><a href="./core">XiHan.Framework.Core</a> — 唯一的框架内部依赖，提供模块化与依赖注入基础。</li></ul><p>第三方存储 SDK 为该包核心依赖：<code>Aliyun.OSS.SDK.NetCore</code>（阿里云 OSS）、<code>Minio</code>（MinIO）、<code>Tencent.QCloud.Cos.Sdk</code>（腾讯云 COS）。</p><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./virtual-file-system">XiHan.Framework.VirtualFileSystem</a> — 虚拟文件系统，偏向本地物理目录与嵌入资源的统一挂载。</li></ul>`,24)])])}const k=a(d,[["render",r]]);export{g as __pageData,k as default};
